import{_ as o,o as a,c as l,a3 as r}from"./chunks/framework.aYYe0dfI.js";const h=JSON.parse('{"title":"Namespace clore::logging","description":"clore::logging 命名空间提供了基于 spdlog 的分级日志记录基础设施。核心机制是通过一组编译时常量代理对象（LogProxy），如 trace、debug、info、warn、err，让调用者以类型安全且高效的方式按指定严重级别输出日志消息。该命名空间同时包含底层日志函数（log）、直接输出到标准错误的便捷函数（stderr_logger）、用于监控缓存命中率的专用函数（cache_hit_rate）以及一个全局日志级别控制变量（g_log_level），共同构成了 clore 库中统一且灵活的日志记录层。","frontmatter":{"title":"Namespace clore::logging","description":"clore::logging 命名空间提供了基于 spdlog 的分级日志记录基础设施。核心机制是通过一组编译时常量代理对象（LogProxy），如 trace、debug、info、warn、err，让调用者以类型安全且高效的方式按指定严重级别输出日志消息。该命名空间同时包含底层日志函数（log）、直接输出到标准错误的便捷函数（stderr_logger）、用于监控缓存命中率的专用函数（cache_hit_rate）以及一个全局日志级别控制变量（g_log_level），共同构成了 clore 库中统一且灵活的日志记录层。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/namespaces/clore/logging/index.md","filePath":"zh/clore/namespaces/clore/logging/index.md"}'),t={name:"zh/clore/namespaces/clore/logging/index.md"};function i(g,e,c,n,s,d){return a(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="namespace-clore-logging" tabindex="-1">Namespace <code>clore::logging</code> <a class="header-anchor" href="#namespace-clore-logging" aria-label="Permalink to &quot;Namespace `clore::logging`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>clore::logging</code> 命名空间提供了基于 <code>spdlog</code> 的分级日志记录基础设施。核心机制是通过一组编译时常量代理对象（<code>LogProxy</code>），如 <code>trace</code>、<code>debug</code>、<code>info</code>、<code>warn</code>、<code>err</code>，让调用者以类型安全且高效的方式按指定严重级别输出日志消息。该命名空间同时包含底层日志函数（<code>log</code>）、直接输出到标准错误的便捷函数（<code>stderr_logger</code>）、用于监控缓存命中率的专用函数（<code>cache_hit_rate</code>）以及一个全局日志级别控制变量（<code>g_log_level</code>），共同构成了 clore 库中统一且灵活的日志记录层。</p><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-logging-logproxy" tabindex="-1"><code>clore::logging::LogProxy</code> <a class="header-anchor" href="#clore-logging-logproxy" aria-label="Permalink to &quot;`clore::logging::LogProxy`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:112</code></p><p>Definition: <code>support/logging.cppm:112</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p>Insufficient evidence to summarize; provide more EVIDENCE.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>The template argument <code>Level</code> must be a valid <code>spdlog::level::level_enum</code> value.</li><li>All calls to <code>operator()</code> eventually invoke <code>log</code> with the same <code>Level</code>.</li><li>The formatted overload requires at least one argument to avoid ambiguity with the plain-string overload.</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>void operator()(std::string_view msg) const</code></li><li><code>void operator()(std::format_string&lt;Args...&gt; fmt, Args&amp;&amp;... args) const</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Instantiated for each log level (e.g., <code>LogProxy&lt;spdlog::level::info&gt;</code>) to create level-specific logging functors.</li><li>Used as a building block for higher-level logging macros or wrapper objects that capture a level.</li><li>Invoked call-site code to log messages without specifying the level explicitly.</li></ul><h4 id="member-functions" tabindex="-1">Member Functions <a class="header-anchor" href="#member-functions" aria-label="Permalink to &quot;Member Functions&quot;">​</a></h4><h5 id="clore-logging-logproxy-operator" tabindex="-1"><code>clore::logging::LogProxy::operator()</code> <a class="header-anchor" href="#clore-logging-logproxy-operator" aria-label="Permalink to &quot;`clore::logging::LogProxy::operator()`&quot;">​</a></h5><p>Declaration: <code>support/logging.cppm:119</code></p><p>Definition: <code>support/logging.cppm:119</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><h6 id="declaration" tabindex="-1">Declaration <a class="header-anchor" href="#declaration" aria-label="Permalink to &quot;Declaration&quot;">​</a></h6><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, Args </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h5 id="clore-logging-logproxy-operator-1" tabindex="-1"><code>clore::logging::LogProxy::operator()</code> <a class="header-anchor" href="#clore-logging-logproxy-operator-1" aria-label="Permalink to &quot;`clore::logging::LogProxy::operator()`&quot;">​</a></h5><p>Declaration: <code>support/logging.cppm:113</code></p><p>Definition: <code>support/logging.cppm:113</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><h6 id="declaration-1" tabindex="-1">Declaration <a class="header-anchor" href="#declaration-1" aria-label="Permalink to &quot;Declaration&quot;">​</a></h6><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::string_view) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h2 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;Variables&quot;">​</a></h2><h3 id="clore-logging-debug" tabindex="-1"><code>clore::logging::debug</code> <a class="header-anchor" href="#clore-logging-debug" aria-label="Permalink to &quot;`clore::logging::debug`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:125</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p><code>clore::logging::debug</code> 是一个 <code>constexpr inline LogProxy&lt;spdlog::level::debug&gt;</code> 类型的编译时常量，用于调试级别的日志记录。</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>作为日志代理，用于输出调试信息</li></ul><h3 id="clore-logging-err" tabindex="-1"><code>clore::logging::err</code> <a class="header-anchor" href="#clore-logging-err" aria-label="Permalink to &quot;`clore::logging::err`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:128</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p><code>clore::logging::err</code> is a <code>constexpr inline LogProxy&lt;spdlog::level::err&gt;</code> object, representing a compile-time constant proxy for logging messages at the error severity level.</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used as a proxy for logging at error level</li></ul><h3 id="clore-logging-g-log-level" tabindex="-1"><code>clore::logging::g_log_level</code> <a class="header-anchor" href="#clore-logging-g-log-level" aria-label="Permalink to &quot;`clore::logging::g_log_level`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:102</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p><code>clore::logging::g_log_level</code> 是一个类型为 <code>std::optional&lt;spdlog::level::level_enum&gt;</code> 的内联变量，用于存储全局日志级别。</p><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>在 <code>clore::logging::log</code> 中读取以过滤日志级别</li><li>在 <code>clore::logging::stderr_logger</code> 中读取以过滤日志级别</li></ul><h3 id="clore-logging-info" tabindex="-1"><code>clore::logging::info</code> <a class="header-anchor" href="#clore-logging-info" aria-label="Permalink to &quot;`clore::logging::info`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:126</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p>A <code>constexpr inline</code> global variable of type <code>LogProxy&lt;spdlog::level::info&gt;</code> declared at <code>support/logging.cppm:126</code>. It serves as a compile-time proxy object for emitting log messages at the info severity level.</p><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Invoked as a function-like object with a format string and arguments to log at info level</li></ul><h3 id="clore-logging-trace" tabindex="-1"><code>clore::logging::trace</code> <a class="header-anchor" href="#clore-logging-trace" aria-label="Permalink to &quot;`clore::logging::trace`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:124</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p>A <code>constexpr inline</code> variable of type <code>LogProxy&lt;spdlog::level::trace&gt;</code>, declared at <code>support/logging.cppm:124</code>. It serves as a compile-time constant logging proxy for trace-level messages.</p><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>invoked with formatting arguments to log trace messages</li></ul><h3 id="clore-logging-warn" tabindex="-1"><code>clore::logging::warn</code> <a class="header-anchor" href="#clore-logging-warn" aria-label="Permalink to &quot;`clore::logging::warn`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:127</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p><code>clore::logging::warn</code> is a <code>constexpr inline</code> variable of type <code>LogProxy&lt;spdlog::level::warn&gt;</code>, defined at <code>support/logging.cppm:127</code>. It serves as a compile-time logging proxy for warning-level messages.</p><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used as a log proxy to emit warning-level log messages</li><li>referenced in function <code>clore::support::enable_utf8_console</code></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-logging-cache-hit-rate" tabindex="-1"><code>clore::logging::cache_hit_rate</code> <a class="header-anchor" href="#clore-logging-cache-hit-rate" aria-label="Permalink to &quot;`clore::logging::cache_hit_rate`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:138</code></p><p>Definition: <code>support/logging.cppm:138</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p><code>clore::logging::cache_hit_rate</code> 接受一个标签、命中次数和总次数，负责计算并记录缓存命中率。调用者应提供具有语义含义的 <code>std::string_view</code> 标识该缓存，并确保两个 <code>std::size_t</code> 实参非负且总量大于零（以避免除零错误）。该函数不返回任何值，但会将格式化后的比率写入日志系统（通常为 <code>info</code> 级别），便于监控和性能分析。</p><h4 id="usage-patterns-7" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-7" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>用于报告缓存性能统计</li><li>在缓存实现中调用时确保 <code>hits + misses</code> 非零</li><li>通过 <code>info</code> 记录缓存命中率</li></ul><h3 id="clore-logging-log" tabindex="-1"><code>clore::logging::log</code> <a class="header-anchor" href="#clore-logging-log" aria-label="Permalink to &quot;`clore::logging::log`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:104</code></p><p>Definition: <code>support/logging.cppm:104</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p>Declaration: <a href="./functions/log">Declaration</a></p><p><code>clore::logging::log</code> 记录一条具有指定严重级别的日志消息。调用者必须提供有效的 <code>spdlog::level::level_enum</code> 表示日志级别，以及一个 <code>std::string_view</code> 作为消息内容。该函数不返回值，由便捷封装如 <code>clore::logging::LogProxy::operator()</code> 在内部调用，也可直接用于自定义日志记录场景。</p><h4 id="usage-patterns-8" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-8" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>由<code>LogProxy::operator()</code>在日志记录时调用</li><li>用于按级别过滤日志消息</li></ul><h3 id="clore-logging-stderr-logger" tabindex="-1"><code>clore::logging::stderr_logger</code> <a class="header-anchor" href="#clore-logging-stderr-logger" aria-label="Permalink to &quot;`clore::logging::stderr_logger`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:130</code></p><p>Definition: <code>support/logging.cppm:130</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p><code>clore::logging::stderr_logger</code> 是一个日志记录函数，它接受一条消息（以 <code>std::string_view</code> 形式提供）并将其直接输出到标准错误流。调用者只需提供消息内容，无需指定日志级别或额外配置；该函数负责将消息写入 <code>stderr</code>。它适用于不需要分级过滤、仅希望将日志文本发送到标准错误输出的场景。</p><h4 id="usage-patterns-9" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-9" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called once at program startup to initialize logging</li><li>Used to configure logging output to stderr</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore</a></li></ul>',90)])])}const u=o(t,[["render",i]]);export{h as __pageData,u as default};
